/**
 * Password Requirements Component
 * Shows real-time password validation requirements as user types
 */

import React from 'react';
import { useTranslation } from 'react-i18next';

const PasswordRequirements = ({ password }) => {
  const { t } = useTranslation('auth');

  const requirements = [
    {
      key: 'length',
      test: (pwd) => pwd.length >= 8,
      message: t('passwordMinLength', { defaultValue: 'At least 8 characters' })
    },
    {
      key: 'uppercase',
      test: (pwd) => /[A-Z]/.test(pwd),
      message: t('passwordMustContainUppercase', { defaultValue: 'One uppercase letter' })
    },
    {
      key: 'lowercase',
      test: (pwd) => /[a-z]/.test(pwd),
      message: t('passwordMustContainLowercase', { defaultValue: 'One lowercase letter' })
    },
    {
      key: 'number',
      test: (pwd) => /[0-9]/.test(pwd),
      message: t('passwordMustContainNumber', { defaultValue: 'One number' })
    },
    {
      key: 'special',
      test: (pwd) => /[^a-zA-Z0-9\s]/.test(pwd), // Allow all special characters (any non-alphanumeric, non-whitespace)
      message: t('passwordMustContainSpecial', { defaultValue: 'One special character' })
    }
  ];

  if (!password) {
    return null;
  }

  return (
    <div style={{
      marginTop: '8px',
      padding: '12px',
      backgroundColor: 'var(--bg-input, rgba(255, 255, 255, 0.1))',
      borderRadius: '8px',
      border: '1px solid var(--border-secondary, rgba(255, 255, 255, 0.2))',
      fontSize: '12px'
    }}>
      <p style={{
        margin: '0 0 8px 0',
        fontWeight: '600',
        color: 'var(--text-primary, #333)',
        fontSize: '13px'
      }}>
        {t('passwordRequirements', { defaultValue: 'Password must contain:' })}
      </p>
      <ul style={{
        margin: 0,
        paddingLeft: '20px',
        listStyle: 'none'
      }}>
        {requirements.map((req) => {
          const isValid = req.test(password);
          return (
            <li
              key={req.key}
              style={{
                marginBottom: '6px',
                display: 'flex',
                alignItems: 'center',
                gap: '8px',
                color: isValid 
                  ? 'var(--success, #23bd00)' 
                  : 'var(--text-muted, #6b7280)',
                transition: 'color 0.2s ease'
              }}
            >
              <span style={{
                fontSize: '14px',
                display: 'flex',
                alignItems: 'center',
                justifyContent: 'center',
                width: '16px',
                height: '16px',
                flexShrink: 0
              }}>
                {isValid ? '✓' : '○'}
              </span>
              <span style={{
                textDecoration: isValid ? 'none' : 'none',
                opacity: isValid ? 1 : 0.7
              }}>
                {req.message}
              </span>
            </li>
          );
        })}
      </ul>
    </div>
  );
};

export default PasswordRequirements;

